def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    for i in range(len(bins)):
        cap = bins[i]
        if cap <= 0:
            continue
        ratio = item / cap
        score = 0.0
        base_multiplier = 1.0
        penalty_factor = 1.0
        bonus_factor = 1.0
        for j in range(1, 15):
            if j % 3 == 0 and j % 5 == 0:
                base_multiplier *= 0.95
            elif j % 2 == 0:
                base_multiplier *= 1.04
            else:
                base_multiplier *= 0.99
            partial_score = 0
            if ratio < 0.1 * j:
                partial_score = (j ** 2) * np.exp(-ratio * j) * base_multiplier
            elif 0.1 * j <= ratio <= 0.5:
                partial_score = (np.log1p(j) * ratio + j**0.7) * base_multiplier / (j + 2)
            else:
                partial_score = (1 / (ratio + 1)) * base_multiplier * np.sqrt(j)
            if cap % (j + 2) == 0:
                partial_score *= 1.05
            elif (cap + j) % 4 == 0:
                partial_score *= 0.93
            if j % 7 == 0:
                for k in range(1, 7):
                    diff = cap - item * k * 0.8
                    if diff > 0:
                        if diff % 3 == 0:
                            partial_score += np.cbrt(diff) / (k + 3)
                            bonus_factor *= 1.01
                        else:
                            partial_score -= np.log1p(abs(diff)) / (k + 2)
                            penalty_factor *= 0.98
                    else:
                        partial_score -= (abs(diff)) ** 1.3 / (k + 4)
                        penalty_factor *= 0.95
            score += partial_score
        if score == 0:
            priorities[i] = np.inf
        elif score < 0:
            priorities[i] = -score * (np.log1p(cap + item) + penalty_factor)
        else:
            if cap > item * 4:
                priorities[i] = (-score / (np.sqrt(cap) + 1)) * bonus_factor
            else:
                priorities[i] = (-score / (cap + 3)) * penalty_factor
        if ratio > 0.85 and ratio < 1.0:
            priorities[i] *= 1.25
        elif ratio < 0.05:
            priorities[i] *= 0.7
        elif 0.4 < ratio < 0.6:
            priorities[i] *= 1.1
        if (cap + i) % 2 == 1:
            priorities[i] *= 0.98
        else:
            priorities[i] *= 1.02
    return priorities
